import { useContext } from "react";
import { AppContext } from "../../../store/app-context";
import SidebarItemWrapper from "./SidebarItemWrapper";
import NotificationBadge from "./NotificationBadge";
import classes from "./SidebarIcon.module.css";

const SidebarIcon = (props) => {
  const ctx = useContext(AppContext);

  let isSelected = false;
  if (ctx.selectedSidebarItem === props.id) {
    isSelected = true;
  }

  const clickHandler = () => {
    ctx.setSelectedSidebarItem(props.id);
  };
  
  return (
    <SidebarItemWrapper onClick={clickHandler}>
      <div className={classes["pill-wrapper"]}>
        {/* Change to animated */}
        {isSelected && <span className={classes["pill"]}></span>}
      </div>

      <div className={classes["server-item-wrapper"]}>
        <div
          className={`${classes["icon-wrapper"]} ${
            isSelected && classes["selected"]
          }`}
        >
          <img
            className={classes["icon"]}
            src="https://animedao.to/images/call-of-the-night.jpg"
            alt="test"
          ></img>
          {/* <div className={classes["icon"]}>G</div> */}
        </div>
        <div className={classes["lower-badge"]}>
          <NotificationBadge amount={1}></NotificationBadge>
        </div>
      </div>
    </SidebarItemWrapper>
  );
};

export default SidebarIcon;
